# Contexto com dados compartilhados
@click.group()
@click.option('--debug', is_flag=True)
@click.pass_context
def cli_shared(ctx, debug):
    """CLI com contexto compartilhado"""
    ctx.ensure_object(dict)
    ctx.obj['debug'] = debug
    ctx.obj['verbose'] = False

@cli_shared.command()
@click.option('--verbose', is_flag=True)
@click.pass_context
def status(ctx, verbose):
