    def __init__(self):
        self.debug = False
        self.data = {}

@click.group()
@click.pass_context
def cli_config(ctx):
    """CLI com configuraГ§ГЈo"""
    ctx.obj = Config()

@cli_config.command()
@click.option('--key')
@click.option('--value')
@click.pass_context
def set(ctx, key, value):
    """Define valor"""
    ctx.obj.data[key] = value
    click.echo(f'Definido {key} = {value}')

@cli_config.command()
@click.argument('key')
