# Exemplo 1: Alertar sobre exclusГөes
class DeletionAlertHandler(FileSystemEventHandler):
    def __init__(self, critical_extensions=None):
        super().__init__()
        self.critical_extensions = critical_extensions or ['.py', '.json', '.db']

    def on_deleted(self, event):
        path = Path(event.src_path)
        timestamp = datetime.now().strftime('%H:%M:%S')

        if event.is_directory:
            print(f'[{timestamp}] вҡ  DIRETГ“RIO DELETADO: {event.src_path}')
            return

        if path.suffix in self.critical_extensions:
            print(f'[{timestamp}] рҹҡЁ CRГҚTICO - Arquivo deletado: {path.name}')
            print(f'  ExtensГЈo crГӯtica: {path.suffix}')
            print(f'  Caminho: {event.src_path}')
            # Em produГ§ГЈo: enviar alerta, email, webhook
        else:
            print(f'[{timestamp}] в„№ Arquivo deletado: {path.name}')

# Exemplo 2: Lixeira automГЎtica (registrar exclusГөes)
class TrashLogHandler(FileSystemEventHandler):
    def __init__(self, log_file='/tmp/deleted_files.log'):
        super().__init__()
        self.log_file = Path(log_file)

    def on_deleted(self, event):
        if event.is_directory:
            tipo = 'DIR'
        else:
            tipo = 'FILE'
        timestamp = datetime.now().isoformat()
        log_entry = f'{timestamp} | {tipo} | {event.src_path}\n'
        print(f'[LOG] {log_entry.strip()}')
        # Em produГ§ГЈo: self.log_file.open('a').write(log_entry)

