import time
from pathlib import Path
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler

# Exemplo 1: Rastrear renomeaГ§Гөes e movimentaГ§Гөes
class MoveTracker(FileSystemEventHandler):
    def on_moved(self, event):
        src = Path(event.src_path)
        dest = Path(event.dest_path)

        if event.is_directory:
            print(f'[DIR MOVIDO]')
        else:
            print(f'[ARQUIVO MOVIDO]')

        print(f'  De:   {src}')
        print(f'  Para: {dest}')

        # Detectar se foi renomeaГ§ГЈo ou movimentaГ§ГЈo
        if src.parent == dest.parent:
            print(f'  Tipo: RENOMEAГҮГғO ({src.name} -> {dest.name})')
        else:
            print(f'  Tipo: MOVIMENTAГҮГғO (de {src.parent.name}/ para {dest.parent.name}/)')

        # Detectar mudanГ§a de extensГЈo
        if src.suffix != dest.suffix:
            print(f'  ExtensГЈo alterada: {src.suffix} -> {dest.suffix}')

# Exemplo 2: Auto-organizaГ§ГЈo de downloads
class DownloadOrganizer(FileSystemEventHandler):
    EXTENSOES = {
        '.pdf': 'Documentos',
        '.doc': 'Documentos', '.docx': 'Documentos',
        '.jpg': 'Imagens', '.png': 'Imagens', '.gif': 'Imagens',
        '.mp4': 'Videos', '.avi': 'Videos',
        '.mp3': 'Musica', '.flac': 'Musica',
        '.zip': 'Compactados', '.tar': 'Compactados', '.gz': 'Compactados',
    }

    def on_created(self, event):
        if event.is_directory:
            return
        path = Path(event.src_path)
        destino_pasta = self.EXTENSOES.get(path.suffix.lower())
        if destino_pasta:
            destino = path.parent / destino_pasta / path.name
            print(f'[ORGANIZAR] {path.name} -> {destino_pasta}/')
            # Em produГ§ГЈo: destino.parent.mkdir(exist_ok=True); path.rename(destino)

    def on_moved(self, event):
        if event.is_directory:
            return
        dest = Path(event.dest_path)
        # Arquivo pode ter sido renomeado apГіs download (padrГЈo do Chrome)
        if dest.suffix in self.EXTENSOES:
            destino_pasta = self.EXTENSOES[dest.suffix.lower()]
            print(f'[ORGANIZAR MOVIDO] {dest.name} -> {destino_pasta}/')

observer = Observer()
observer.schedule(MoveTracker(), path='/tmp/monitorado', recursive=True)
observer.start()

try:
    while True:
        time.sleep(1)
except KeyboardInterrupt:
    observer.stop()
observer.join()

import time
from pathlib import Path
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler

# Exemplo 1: Processar arquivo somente quando escrita terminar
class SafeProcessHandler(FileSystemEventHandler):
    """Usa on_closed em vez de on_created/on_modified para garantir
    que o arquivo estГЎ completo antes de processar"""

    def on_closed(self, event):
        """Chamado quando arquivo Г© fechado apГіs escrita (Linux/inotify)"""
        if event.is_directory:
            return

        path = Path(event.src_path)
        print(f'[ARQUIVO FECHADO] {path.name}')
        print(f'  -> Arquivo completo, seguro para processar')

        try:
            tamanho = path.stat().st_size
            print(f'  -> Tamanho final: {tamanho} bytes')
        except FileNotFoundError:
            print(f'  -> Arquivo jГЎ foi removido')

    def on_created(self, event):
        if event.is_directory:
            return
        print(f'[CRIADO] {Path(event.src_path).name} (escrita pode estar em andamento...)')

    def on_modified(self, event):
        if event.is_directory:
            return
        print(f'[MODIFICADO] {Path(event.src_path).name} (escrita em andamento...)')

# Exemplo 2: Upload completo detection
class UploadCompleteHandler(FileSystemEventHandler):
    def on_closed(self, event):
        if event.is_directory:
            return
        path = Path(event.src_path)
        if path.suffix in ('.csv', '.xlsx', '.json'):
            print(f'[UPLOAD COMPLETO] {path.name}')
            print(f'  -> Iniciando importaГ§ГЈo...')

# NOTA: on_closed sГі funciona no Linux com backend inotify
# Em macOS/Windows, use on_modified com debounce como alternativa

observer = Observer()
observer.schedule(SafeProcessHandler(), path='/tmp/uploads', recursive=False)
observer.start()

try:
    while True:
        time.sleep(1)
except KeyboardInterrupt:
    observer.stop()
observer.join()

