# Exemplo 2: Erro ao acessar arquivo no handler
class SafeReadHandler(FileSystemEventHandler):
    def on_modified(self, event):
        if event.is_directory:
            return
        try:
            conteudo = Path(event.src_path).read_text()
            print(f'Lido: {Path(event.src_path).name} ({len(conteudo)} chars)')
        except PermissionError:
            print(f'Sem permissГЈo para ler: {event.src_path}')
        except FileNotFoundError:
