            print(f'Erro inesperado: {type(e).__name__}: {e}')

# Exemplo 3: Verificar permissГөes antes
import os

def pode_monitorar(caminho):
    """Verifica se tem permissГЈo para monitorar o diretГіrio"""
    path = Path(caminho)
    if not path.exists():
        print(f'вқҢ NГЈo existe: {caminho}')
        return False
    if not path.is_dir():
        print(f'вқҢ NГЈo Г© diretГіrio: {caminho}')
        return False
    if not os.access(caminho, os.R_OK):
        print(f'вқҢ Sem permissГЈo de leitura: {caminho}')
        return False
    print(f'вң… OK para monitorar: {caminho}')
    return True

pode_monitorar('/tmp')
pode_monitorar('/root')
pode_monitorar('/caminho/inexistente')

