# PROBLEMA: Handler sem tratamento de erro
class HandlerFragil(FileSystemEventHandler):
    def on_modified(self, event):
        # Se isso falhar, o evento Г© perdido silenciosamente!
        conteudo = Path(event.src_path).read_text()
        dados = conteudo.split(',')
