# SOLUГҮГғO 1: try/except em cada mГ©todo
class HandlerRobusto(FileSystemEventHandler):
    def on_modified(self, event):
        try:
            if event.is_directory:
                return
            conteudo = Path(event.src_path).read_text(errors='replace')
            print(f'Modificado: {Path(event.src_path).name}')
        except Exception as e:
            print(f'Erro no handler: {type(e).__name__}: {e}')

# SOLUГҮГғO 2: Decorator para tratamento de erro
def safe_handler(func):
    def wrapper(self, event):
        try:
            return func(self, event)
        except Exception as e:
            logging.error(f'Erro em {func.__name__}: {e}', exc_info=True)
    return wrapper

class HandlerComDecorator(FileSystemEventHandler):
    @safe_handler
    def on_created(self, event):
        print(f'Criado: {event.src_path}')
        # CГіdigo que pode falhar...

    @safe_handler
    def on_modified(self, event):
        print(f'Modificado: {event.src_path}')

# SOLUГҮГғO 3: Handler base com tratamento centralizado
class SafeBaseHandler(FileSystemEventHandler):
    """Handler base que captura todas as exceГ§Гөes"""

    def dispatch(self, event):
        try:
            super().dispatch(event)
        except Exception:
            logging.error(
                f'ExceГ§ГЈo nГЈo tratada no handler para {event.src_path}',
                exc_info=True
            )

class MeuHandlerSeguro(SafeBaseHandler):
    def on_created(self, event):
