import schedule
import time
import functools
from datetime import datetime

# ============================================
# ABORDAGEM 1: Decorador simples (manual)
# ============================================

def repeat(intervalo_job):
    """Decorador que agenda a funГ§ГЈo automaticamente"""
    def decorator(func):
        intervalo_job.do(func)
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            return func(*args, **kwargs)
        return wrapper
    return decorator

# Uso do decorador manual
@repeat(schedule.every(5).seconds)
def heartbeat():
    print(f'[{datetime.now().strftime("%H:%M:%S")}] вқӨпёҸ heartbeat')

@repeat(schedule.every(10).seconds)
def verificar_disco():
    print(f'[{datetime.now().strftime("%H:%M:%S")}] рҹ’ҫ Disco OK')

@repeat(schedule.every().hour.at(':00'))
def relatorio_hora():
    print(f'[{datetime.now().strftime("%H:%M:%S")}] рҹ“Ҡ RelatГіrio da hora')

print(f'Jobs agendados via decorador: {len(schedule.get_jobs())}')

# ============================================
# ABORDAGEM 2: Decorador com schedule.repeat() (v1.1.0+)
# ============================================

# A partir da versГЈo 1.1.0, schedule tem decorador nativo:

@schedule.repeat(schedule.every(3).seconds)
def ping():
    print(f'[{datetime.now().strftime("%H:%M:%S")}] рҹҸ“ ping')

@schedule.repeat(schedule.every().minute.at(':15'))
def check_queue():
    print(f'[{datetime.now().strftime("%H:%M:%S")}] рҹ“¬ Verificando fila')

@schedule.repeat(schedule.every().day.at('09:00'), 'relatГіrio diГЎrio')
def relatorio_diario():
    print('Gerando relatГіrio...')

# ============================================
# ABORDAGEM 3: Decorador com tags
# ============================================

def scheduled(job_config, *tags):
    """Decorador com suporte a tags"""
    def decorator(func):
        job = job_config.do(func)
        for tag in tags:
            job.tag(tag)
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            return func(*args, **kwargs)
        return wrapper
    return decorator

@scheduled(schedule.every(5).seconds, 'monitoramento', 'critico')
def monitor_cpu():
    print('CPU: OK')

@scheduled(schedule.every(30).seconds, 'monitoramento')
def monitor_memoria():
    print('RAM: OK')

print(f'\nTotal de jobs: {len(schedule.get_jobs())}')
print(f'Jobs "monitoramento": {len(schedule.get_jobs("monitoramento"))}')

schedule.clear()

import schedule
import time
import logging
import functools
from datetime import datetime

logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s [%(levelname)s] %(message)s',
    datefmt='%H:%M:%S'
)
logger = logging.getLogger(__name__)

# ============================================
# PROBLEMA: ExceГ§ГЈo nГЈo tratada para o scheduler
# ============================================
# Por padrГЈo, se um job lanГ§ar exceГ§ГЈo, ela NГғO Г© capturada
# e pode interromper o loop run_pending()

# ============================================
# SOLUГҮГғO 1: Wrapper catch_exceptions
# ============================================

def catch_exceptions(job_func, cancel_on_failure=False):
    """Wrapper que captura exceГ§Гөes do job"""
    @functools.wraps(job_func)
    def wrapper(*args, **kwargs):
        try:
            return job_func(*args, **kwargs)
        except Exception as e:
            logger.error(f'Erro no job {job_func.__name__}: {e}', exc_info=True)
            if cancel_on_failure:
                logger.warning(f'Cancelando job {job_func.__name__}')
                return schedule.CancelJob
    return wrapper

def tarefa_instavel():
    import random
    if random.random() < 0.3:
        raise ConnectionError('Falha de conexГЈo com o servidor')
    print('Tarefa executada com sucesso!')

# Uso: job continua mesmo com erro
schedule.every(2).seconds.do(catch_exceptions(tarefa_instavel))

# Uso: job cancela apГіs falha
schedule.every(5).seconds.do(catch_exceptions(tarefa_instavel, cancel_on_failure=True))

# ============================================
# SOLUГҮГғO 2: Decorador com retry
# ============================================

def with_retry(max_retries=3, delay=1):
    """Decorador que faz retry em caso de falha"""
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for tentativa in range(1, max_retries + 1):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    logger.warning(f'{func.__name__} falhou (tentativa {tentativa}/{max_retries}): {e}')
                    if tentativa < max_retries:
                        time.sleep(delay)
                    else:
                        logger.error(f'{func.__name__} falhou apГіs {max_retries} tentativas')
        return wrapper
    return decorator

@with_retry(max_retries=3, delay=0.5)
def enviar_dados():
    import random
    if random.random() < 0.7:
        raise TimeoutError('Timeout ao enviar')
    print('Dados enviados com sucesso!')

schedule.every(10).seconds.do(enviar_dados)

# ============================================
# SOLUГҮГғO 3: Loop principal seguro
# ============================================

print('=== Loop seguro ===')
for i in range(5):
    try:
        schedule.run_pending()
    except Exception as e:
        logger.error(f'Erro no scheduler: {e}')
    time.sleep(1)

# ============================================
# SOLUГҮГғO 4: Decorador genГ©rico safe_schedule
# ============================================

def safe_job(func):
    """Decorador universal para jobs seguros"""
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        try:
            resultado = func(*args, **kwargs)
            logger.info(f'вң… {func.__name__} concluГӯdo')
            return resultado
        except Exception as e:
            logger.error(f'вқҢ {func.__name__} falhou: {e}')
            # NГЈo propaga a exceГ§ГЈo - job continua agendado
    return wrapper

@safe_job
def tarefa_protegida():
    print('Executando tarefa protegida...')
    raise RuntimeError('Algo deu errado!')

schedule.every(3).seconds.do(tarefa_protegida)

for i in range(3):
    schedule.run_pending()
    time.sleep(1)

schedule.clear()

import schedule
import time
import json
import logging
from datetime import datetime
from pathlib import Path

# ============================================
# Configurar logging profissional
# ============================================

logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s [%(name)s] %(levelname)s: %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S',
    handlers=[
        logging.StreamHandler(),
        logging.FileHandler('/tmp/scheduler.log')
    ]
)
logger = logging.getLogger('Scheduler')

# ============================================
# Wrapper que loga execuГ§Гөes automaticamente
# ============================================

def logged_job(func):
    """Decorador que adiciona logging automГЎtico"""
    def wrapper(*args, **kwargs):
        nome = func.__name__
        logger.info(f'вҸі Iniciando: {nome}')
        inicio = time.time()
        try:
            resultado = func(*args, **kwargs)
            duracao = time.time() - inicio
            logger.info(f'вң… ConcluГӯdo: {nome} ({duracao:.2f}s)')
            return resultado
        except Exception as e:
            duracao = time.time() - inicio
            logger.error(f'вқҢ Falhou: {nome} ({duracao:.2f}s) - {e}')
    return wrapper

@logged_job
def processar_dados():
    time.sleep(0.5)  # simula processamento
    return 'dados processados'

@logged_job
def enviar_relatorio():
    time.sleep(0.3)
    return 'relatГіrio enviado'

schedule.every(5).seconds.do(processar_dados)
schedule.every(10).seconds.do(enviar_relatorio)

# ============================================
# PersistГӘncia de estado dos jobs
# ============================================

class PersistentScheduler:
    """Scheduler que salva estado para sobreviver a restarts"""

    def __init__(self, state_file='/tmp/scheduler_state.json'):
        self.state_file = Path(state_file)
        self.executions = {}
        self._load_state()

    def _load_state(self):
        if self.state_file.exists():
            try:
                data = json.loads(self.state_file.read_text())
                self.executions = data.get('executions', {})
                logger.info(f'Estado carregado: {len(self.executions)} jobs')
            except json.JSONDecodeError:
                logger.warning('Estado corrompido, iniciando limpo')
                self.executions = {}

    def save_state(self):
        data = {
            'last_save': datetime.now().isoformat(),
            'executions': self.executions
        }
        self.state_file.write_text(json.dumps(data, indent=2))

    def track(self, job_name):
        """Decorador que rastreia execuГ§Гөes"""
        def decorator(func):
            def wrapper(*args, **kwargs):
                resultado = func(*args, **kwargs)
                self.executions[job_name] = {
                    'Гәltima_execuГ§ГЈo': datetime.now().isoformat(),
                    'total_execuГ§Гөes': self.executions.get(job_name, {}).get('total_execuГ§Гөes', 0) + 1
                }
                self.save_state()
                return resultado
            return wrapper
        return decorator

ps = PersistentScheduler()

