def criar_soup(html, parser_preferido='lxml'):
    """Tenta usar o parser preferido com fallback"""
    parsers = [parser_preferido, 'html.parser', 'html5lib']
    for parser in parsers:
        try:
            return BeautifulSoup(html, parser)
        except FeatureNotFound:
            continue
    raise RuntimeError('Nenhum parser disponГӯvel!')

