# Downloader Middleware
class CustomDownloaderMiddleware:
    def process_request(self, request, spider):
        # Adiciona user agent customizado
        request.headers['User-Agent'] = 'MyCustomBot/1.0'
        return None  # Continua processamento normal

    def process_response(self, request, response, spider):
        # Log de respostas com erro
        if response.status >= 400:
            spider.logger.warning(f"Error {response.status} for {request.url}")
        return response

    def process_exception(self, request, exception, spider):
        # Retry em caso de timeout
        if isinstance(exception, TimeoutError):
            return request.replace(dont_filter=True)
        return None

# Spider Middleware
class CustomSpiderMiddleware:
    def process_spider_input(self, response, spider):
        # Processa antes de passar para o spider
        return None

    def process_spider_output(self, response, result, spider):
        # Processa os items/requests gerados pelo spider
        for item_or_request in result:
            if isinstance(item_or_request, dict):
                item_or_request['processed_by_middleware'] = True
            yield item_or_request

# Middleware com proxy rotativo
class RotatingProxyMiddleware:
    def __init__(self):
        self.proxies = ['http://proxy1:8080', 'http://proxy2:8080']
        self.current = 0

    def process_request(self, request, spider):
        proxy = self.proxies[self.current]
        self.current = (self.current + 1) % len(self.proxies)
        request.meta['proxy'] = proxy

# Middleware com retry
class RetryMiddleware:
    def process_response(self, request, response, spider):
        if response.status in [500, 502, 503, 504]:
            return request.replace(dont_filter=True)
        return response

# Middleware com cache
class CacheMiddleware:
    def __init__(self):
        self.cache = {}

    def process_request(self, request, spider):
        if request.url in self.cache:
            return HtmlResponse(url=request.url, body=self.cache[request.url])
        return None

    def process_response(self, request, response, spider):
        self.cache[request.url] = response.body
        return response

