import httpx

try:
    response = httpx.get("https://httpbin.org/status/404")
    response.raise_for_status()
except httpx.HTTPStatusError as e:
    print(f"Erro {e.response.status_code}: {e.request.url}")
    print(f"Resposta: {e.response.text[:100]}")

# Capturando diferentes status codes
try:
    response = httpx.get("https://httpbin.org/status/500")
    response.raise_for_status()
except httpx.HTTPStatusError as e:
    if e.response.status_code == 404:
        print("Recurso nГЈo encontrado")
    elif e.response.status_code == 500:
        print("Erro interno do servidor")
    else:
        print(f"Erro: {e.response.status_code}")

# Tratamento em cliente com retry
client = httpx.Client()
max_retries = 3
for attempt in range(max_retries):
    try:
        response = client.get("https://api.example.com/unstable")
        response.raise_for_status()
        break
    except httpx.HTTPStatusError as e:
        if e.response.status_code >= 500 and attempt < max_retries - 1:
            print(f"Tentativa {attempt + 1} falhou, retentando...")
            continue
        raise

# Acessando detalhes do erro
try:
    response = httpx.get("https://httpbin.org/status/403")
    response.raise_for_status()
except httpx.HTTPStatusError as e:
    print(f"URL: {e.request.url}")
    print(f"Method: {e.request.method}")
    print(f"Status: {e.response.status_code}")
    print(f"Reason: {e.response.reason_phrase}")

# Classe especГӯfica para 404
from httpx import HTTPStatusError

try:
    response = httpx.get("https://httpbin.org/status/404")
    response.raise_for_status()
except HTTPStatusError as e:
    if e.response.status_code == 404:
        print("404 - Not Found")
    raise

# Timeout bГЎsico
import httpx

try:
    response = httpx.get("https://httpbin.org/delay/10", timeout=2.0)
except httpx.TimeoutException as e:
    print(f"Timeout: {e}")
    print(f"Request URL: {e.request.url}")

# Timeout detalhado por tipo
try:
    timeout = httpx.Timeout(connect=1.0, read=5.0, write=2.0, pool=1.0)
    response = httpx.get("https://httpbin.org/delay/6", timeout=timeout)
except httpx.ConnectTimeout:
    print("Falha na conexГЈo")
except httpx.ReadTimeout:
    print("Timeout na leitura da resposta")
except httpx.WriteTimeout:
    print("Timeout no envio de dados")
except httpx.PoolTimeout:
    print("Timeout no pool de conexГөes")

# Timeout com retry
import time

for attempt in range(3):
    try:
        response = httpx.get("https://slow-api.example.com/data", timeout=5.0)
        break
    except httpx.TimeoutException:
        if attempt == 2:
            raise
        print(f"Timeout, tentativa {attempt + 1}/3")
        time.sleep(2)

# Timeout apenas para conexГЈo, sem limite para leitura
response = httpx.get("https://streaming.example.com/data", timeout=httpx.Timeout(connect=3.0, read=None))

# Timeout infinito (None)
response = httpx.get("https://httpbin.org/delay/30", timeout=None)  # Espera indefinidamente

# Timeout em cliente com contexto
with httpx.Client(timeout=3.0) as client:
    try:
        response = client.get("https://httpbin.org/delay/5")
    except httpx.TimeoutException:
        print("Cliente excedeu timeout")

# Timeout em requisiГ§ГЈo especГӯfica sobrescreve cliente
client = httpx.Client(timeout=10.0)
response = client.get("https://httpbin.org/delay/2", timeout=1.0)  # Timeout menor

# Timeout com streaming
with httpx.stream("GET", "https://httpbin.org/stream/100", timeout=2.0) as response:
    try:
        for chunk in response.iter_bytes():
            print(f"Chunk: {len(chunk)}")
    except httpx.ReadTimeout:
        print("Timeout durante streaming")

# Erro de conexГЈo bГЎsico
import httpx

try:
    response = httpx.get("https://dominio-inexistente.xyz")
except httpx.ConnectError as e:
    print(f"Erro de conexГЈo: {e}")
    print(f"Request URL: {e.request.url}")

# DNS resolution error
try:
    response = httpx.get("http://invalid-domain-that-does-not-exist.com")
except httpx.ConnectError as e:
    print(f"DNS resolution failed: {e}")

# Connection refused
try:
    response = httpx.get("http://localhost:54321")  # Porta sem serviГ§o
except httpx.ConnectError as e:
    print(f"Connection refused: {e}")

# Network unreachable
try:
    response = httpx.get("http://192.0.2.1")  # IP nГЈo roteГЎvel
except httpx.ConnectError as e:
    print(f"Network unreachable: {e}")

# Tratamento com retry
from tenacity import retry, stop_after_attempt, wait_exponential

@retry(stop=stop_after_attempt(3), wait=wait_exponential(multiplier=1, min=2, max=10))
def fetch_with_retry():
    try:
        return httpx.get("https://unreliable-server.com/api")
    except httpx.ConnectError:
        print("Connection failed, retrying...")
        raise

# Verificando tipo especГӯfico de erro de conexГЈo
try:
    response = httpx.get("https://example.com")
except httpx.ConnectTimeout:
    print("Connection timeout")
except httpx.ConnectError as e:
    if "Name or service not known" in str(e):
        print("DNS error")
    elif "Connection refused" in str(e):
        print("Port closed or service not running")
    else:
        print(f"Other connection error: {e}")

# Erro de conexГЈo com proxy
try:
    proxies = {"http://": "http://invalid-proxy:8080"}
    response = httpx.get("https://httpbin.org/get", proxies=proxies)
except httpx.ProxyError as e:
    print(f"Proxy connection error: {e}")

