from pydantic import BaseModel

app = FastAPI()

# === GET - Leitura ===
@app.get('/')
def raiz():
    return {'status': 'online'}

@app.get('/itens')
def listar_itens():
    return [{'id': 1, 'nome': 'Item A'}, {'id': 2, 'nome': 'Item B'}]

# === POST - CriaГ§ГЈo ===
class ItemCreate(BaseModel):
    nome: str
    preco: float

@app.post('/itens', status_code=201)
def criar_item(item: ItemCreate):
    return {'id': 3, 'nome': item.nome, 'preco': item.preco}

# === PUT - AtualizaГ§ГЈo completa ===
class ItemUpdate(BaseModel):
    nome: str
    preco: float

@app.put('/itens/{item_id}')
def atualizar_item(item_id: int, item: ItemUpdate):
    return {'id': item_id, 'nome': item.nome, 'preco': item.preco}

# === PATCH - AtualizaГ§ГЈo parcial ===
class ItemPatch(BaseModel):
    nome: str | None = None
    preco: float | None = None

@app.patch('/itens/{item_id}')
def patch_item(item_id: int, item: ItemPatch):
    return {'id': item_id, 'atualizado': item.model_dump(exclude_unset=True)}

# === DELETE - RemoГ§ГЈo ===
@app.delete('/itens/{item_id}', status_code=204)
