    nome: str
    preco: float
    em_estoque: bool = True  # valor padrГЈo

@app.post('/itens')
def criar_item(item: ItemCreate):
    return {'id': 1, **item.model_dump()}

# Exemplo 2: Model com Field() para validaГ§Гөes
class Produto(BaseModel):
    nome: str = Field(
        min_length=2,
        max_length=100,
        description='Nome do produto',
        examples=['Notebook Dell']
    )
    preco: float = Field(
        gt=0,
        le=999999.99,
        description='PreГ§o em reais'
    )
    descricao: str | None = Field(
        default=None,
        max_length=500
    )
    tags: list[str] = Field(default_factory=list)

@app.post('/produtos')
def criar_produto(produto: Produto):
    return produto

# Exemplo 3: Models aninhados
class Endereco(BaseModel):
    rua: str
    cidade: str
    estado: str = Field(min_length=2, max_length=2)
    cep: str = Field(pattern=r'^\d{5}-?\d{3}$')

class Usuario(BaseModel):
    nome: str
    email: str
    idade: int = Field(ge=18, le=120)
    endereco: Endereco  # modelo aninhado
    interesses: list[str] = []

@app.post('/usuarios')
def criar_usuario(usuario: Usuario):
    return usuario

# Exemplo 4: Validador customizado
class Pedido(BaseModel):
    produto: str
    quantidade: int = Field(ge=1)
    preco_unitario: float = Field(gt=0)

    @field_validator('produto')
    @classmethod
    def produto_nao_vazio(cls, v):
        if not v.strip():
            raise ValueError('Produto nГЈo pode ser vazio')
        return v.strip()

    @model_validator(mode='after')
    def calcular_total(self):
        self.total = self.quantidade * self.preco_unitario
        return self

    total: float = 0

@app.post('/pedidos')
def criar_pedido(pedido: Pedido):
    return pedido

# Exemplo 5: Body com parГўmetro singular (nГЈo model)
