from fastapi import FastAPI, HTTPException, Request
from fastapi.responses import JSONResponse
from fastapi.exceptions import RequestValidationError
from pydantic import BaseModel

app = FastAPI()

# Banco simulado
usuarios_db = {1: {'nome': 'Ana'}, 2: {'nome': 'Bob'}}

# Exemplo 1: HTTPException bГЎsico
@app.get('/usuarios/{usuario_id}')
def get_usuario(usuario_id: int):
    if usuario_id not in usuarios_db:
        raise HTTPException(
            status_code=404,
            detail='UsuГЎrio nГЈo encontrado'
        )
    return usuarios_db[usuario_id]

# Exemplo 2: HTTPException com headers
@app.get('/protegido')
def rota_protegida():
    raise HTTPException(
        status_code=401,
        detail='Token invГЎlido ou expirado',
        headers={'WWW-Authenticate': 'Bearer'}
    )

# Exemplo 3: Detalhes como dicionГЎrio
@app.delete('/usuarios/{usuario_id}')
def deletar_usuario(usuario_id: int):
    if usuario_id not in usuarios_db:
        raise HTTPException(
            status_code=404,
            detail={
                'mensagem': 'UsuГЎrio nГЈo encontrado',
                'usuario_id': usuario_id,
                'sugestao': 'Verifique o ID informado'
            }
        )
    return {'deletado': True}

# Exemplo 4: ExceГ§ГЈo customizada
class ItemNaoEncontrado(Exception):
    def __init__(self, item_id: int):
        self.item_id = item_id

@app.exception_handler(ItemNaoEncontrado)
async def item_nao_encontrado_handler(request: Request, exc: ItemNaoEncontrado):
    return JSONResponse(
        status_code=404,
        content={
            'erro': 'Item nГЈo encontrado',
            'item_id': exc.item_id,
            'path': str(request.url)
        }
    )

@app.get('/itens/{item_id}')
def get_item(item_id: int):
    if item_id > 100:
        raise ItemNaoEncontrado(item_id)
    return {'item_id': item_id}

# Exemplo 5: Handler global para erros de validaГ§ГЈo
@app.exception_handler(RequestValidationError)
async def validation_exception_handler(request: Request, exc: RequestValidationError):
    return JSONResponse(
        status_code=422,
        content={
            'erro': 'Dados invГЎlidos',
            'detalhes': exc.errors(),
            'body': exc.body
        }
    )

# Exemplo 6: Handler genГ©rico para exceГ§Гөes nГЈo tratadas
@app.exception_handler(Exception)
async def generic_exception_handler(request: Request, exc: Exception):
    return JSONResponse(
        status_code=500,
        content={
            'erro': 'Erro interno do servidor',
            'tipo': type(exc).__name__
        }
    )

# Exemplo 7: Diferentes status codes
@app.post('/processar')
def processar(dados: dict):
    if not dados:
        raise HTTPException(status_code=400, detail='Dados vazios')
    if dados.get('tipo') == 'proibido':
        raise HTTPException(status_code=403, detail='OperaГ§ГЈo proibida')
    if dados.get('tipo') == 'conflito':
        raise HTTPException(status_code=409, detail='Recurso jГЎ existe')
    return {'processado': True}

