from fastapi import FastAPI, Depends, HTTPException, Header, Query
from typing import Annotated

app = FastAPI()

# Exemplo 1: DependГӘncia como funГ§ГЈo simples
def paginacao(skip: int = 0, limit: int = Query(default=10, le=100)):
    return {'skip': skip, 'limit': limit}

@app.get('/itens')
def listar_itens(pag: dict = Depends(paginacao)):
    return {'paginacao': pag, 'itens': []}

@app.get('/usuarios')
def listar_usuarios(pag: dict = Depends(paginacao)):
    return {'paginacao': pag, 'usuarios': []}

# Exemplo 2: DependГӘncia de autenticaГ§ГЈo
def verificar_token(x_token: str = Header()):
    if x_token != 'token-secreto':
        raise HTTPException(status_code=401, detail='Token invГЎlido')
    return x_token

def get_usuario_atual(token: str = Depends(verificar_token)):
    # SubdependГӘncia: depende de verificar_token
    return {'nome': 'Ana', 'token': token}

@app.get('/perfil')
def perfil(usuario: dict = Depends(get_usuario_atual)):
    return {'usuario': usuario}

# Exemplo 3: DependГӘncia como classe
class FiltroItens:
    def __init__(
        self,
        q: str | None = None,
        skip: int = 0,
        limit: int = 10,
        ordenar_por: str = 'nome'
    ):
        self.q = q
        self.skip = skip
        self.limit = limit
        self.ordenar_por = ordenar_por

@app.get('/produtos')
def listar_produtos(filtro: FiltroItens = Depends()):
    return {
        'query': filtro.q,
        'skip': filtro.skip,
        'limit': filtro.limit,
        'ordenar_por': filtro.ordenar_por
    }

# Exemplo 4: Annotated (Python 3.9+ - padrГЈo recomendado)
PaginacaoDep = Annotated[dict, Depends(paginacao)]
UsuarioAtual = Annotated[dict, Depends(get_usuario_atual)]

@app.get('/v2/itens')
def listar_itens_v2(pag: PaginacaoDep, usuario: UsuarioAtual):
    return {'paginacao': pag, 'usuario': usuario['nome']}

# Exemplo 5: DependГӘncias globais (aplicadas em todas as rotas)
async def verificar_api_key(x_api_key: str = Header()):
    if x_api_key != 'chave-valida':
        raise HTTPException(status_code=403, detail='API key invГЎlida')

app_seguro = FastAPI(dependencies=[Depends(verificar_api_key)])

@app_seguro.get('/dados')
def dados_seguros():
    return {'dados': 'secretos'}

# Exemplo 6: DependГӘncia com yield (cleanup/teardown)
def get_db():
    db = {'connection': 'ativa'}  # simula conexГЈo
    print('Abrindo conexГЈo com banco')
    try:
        yield db
    finally:
        print('Fechando conexГЈo com banco')

@app.get('/db-dados')
def ler_dados(db: dict = Depends(get_db)):
    return {'db_status': db['connection']}

