from fastapi import FastAPI, BackgroundTasks
from pydantic import BaseModel
import time

app = FastAPI()

# Exemplo 1: Background task simples
def escrever_log(mensagem: str):
    time.sleep(2)  # simula operaГ§ГЈo demorada
    with open('/tmp/log.txt', 'a') as f:
        f.write(f'{mensagem}\n')
    print(f'Log escrito: {mensagem}')

@app.post('/log')
def criar_log(mensagem: str, background_tasks: BackgroundTasks):
    background_tasks.add_task(escrever_log, mensagem)
    return {'status': 'Log agendado'}  # responde imediatamente

# Exemplo 2: MГәltiplas tasks
def enviar_email(email: str, assunto: str):
    time.sleep(3)
    print(f'Email enviado para {email}: {assunto}')

def atualizar_estatisticas(usuario_id: int):
    time.sleep(1)
    print(f'EstatГӯsticas atualizadas para user {usuario_id}')

class UsuarioCreate(BaseModel):
    nome: str
    email: str

@app.post('/usuarios')
def criar_usuario(usuario: UsuarioCreate, background_tasks: BackgroundTasks):
    # Responde imediatamente
    resultado = {'id': 1, 'nome': usuario.nome}

    # Agenda tarefas em background
    background_tasks.add_task(enviar_email, usuario.email, 'Bem-vindo!')
    background_tasks.add_task(atualizar_estatisticas, 1)
    background_tasks.add_task(escrever_log, f'UsuГЎrio criado: {usuario.nome}')

    return resultado

# Exemplo 3: Background task em dependГӘncia
def notificar_admins(background_tasks: BackgroundTasks):
    def notificar():
        print('Admins notificados')
    background_tasks.add_task(notificar)

@app.post('/acao-importante')
def acao_importante(background_tasks: BackgroundTasks):
    notificar_admins(background_tasks)
    return {'acao': 'completada'}

