            }
            await websocket.send_json(resposta)
    except WebSocketDisconnect:
        pass

# Exemplo 3: Chat com mГәltiplos clientes
class GerenciadorConexoes:
    def __init__(self):
        self.conexoes_ativas: list[WebSocket] = []

    async def conectar(self, websocket: WebSocket):
        await websocket.accept()
        self.conexoes_ativas.append(websocket)

    def desconectar(self, websocket: WebSocket):
        self.conexoes_ativas.remove(websocket)

    async def broadcast(self, mensagem: str):
        for conexao in self.conexoes_ativas:
            await conexao.send_text(mensagem)

gerenciador = GerenciadorConexoes()

@app.websocket('/ws/chat/{nome}')
async def chat(websocket: WebSocket, nome: str):
    await gerenciador.conectar(websocket)
    await gerenciador.broadcast(f'{nome} entrou no chat')
    try:
        while True:
            dados = await websocket.receive_text()
            await gerenciador.broadcast(f'{nome}: {dados}')
    except WebSocketDisconnect:
        gerenciador.desconectar(websocket)
        await gerenciador.broadcast(f'{nome} saiu do chat')

