from fastapi import FastAPI, HTTPException, Query, Path, Depends
from pydantic import BaseModel, Field
from datetime import datetime
from enum import Enum

app = FastAPI(title='API de Produtos', version='1.0.0')

# === Models ===

class CategoriaEnum(str, Enum):
    eletronicos = 'eletronicos'
    roupas = 'roupas'
    alimentos = 'alimentos'
    livros = 'livros'

class ProdutoBase(BaseModel):
    nome: str = Field(min_length=2, max_length=100)
    preco: float = Field(gt=0, le=999999)
    descricao: str | None = Field(default=None, max_length=500)
    categoria: CategoriaEnum
    em_estoque: bool = True

class ProdutoCreate(ProdutoBase):
    pass

class ProdutoUpdate(BaseModel):
    nome: str | None = Field(default=None, min_length=2, max_length=100)
    preco: float | None = Field(default=None, gt=0)
    descricao: str | None = None
    categoria: CategoriaEnum | None = None
    em_estoque: bool | None = None

class ProdutoResponse(ProdutoBase):
    id: int
    criado_em: datetime
    atualizado_em: datetime

class ProdutoListResponse(BaseModel):
    total: int
    pagina: int
    por_pagina: int
    produtos: list[ProdutoResponse]

# === Banco simulado ===
db: dict[int, dict] = {}
sequencia_id = 0

def gerar_id() -> int:
    global sequencia_id
    sequencia_id += 1
    return sequencia_id

# === DependГӘncias ===
def paginacao(
    pagina: int = Query(default=1, ge=1, description='NГәmero da pГЎgina'),
    por_pagina: int = Query(default=10, ge=1, le=100, description='Itens por pГЎgina')
):
    return {'pagina': pagina, 'por_pagina': por_pagina, 'skip': (pagina - 1) * por_pagina}

# === Endpoints ===

@app.post('/produtos', response_model=ProdutoResponse, status_code=201, tags=['Produtos'])
def criar_produto(produto: ProdutoCreate):
    """Cria um novo produto"""
    agora = datetime.now()
    produto_db = {
        'id': gerar_id(),
        **produto.model_dump(),
        'criado_em': agora,
        'atualizado_em': agora
    }
    db[produto_db['id']] = produto_db
    return produto_db

@app.get('/produtos', response_model=ProdutoListResponse, tags=['Produtos'])
def listar_produtos(
    pag: dict = Depends(paginacao),
    q: str | None = Query(default=None, min_length=2, description='Buscar por nome'),
    categoria: CategoriaEnum | None = None,
    em_estoque: bool | None = None,
    ordenar: str = Query(default='nome', pattern='^(nome|preco|criado_em)$'),
):
    """Lista produtos com filtros e paginaГ§ГЈo"""
    resultados = list(db.values())

    if q:
        resultados = [p for p in resultados if q.lower() in p['nome'].lower()]
    if categoria:
        resultados = [p for p in resultados if p['categoria'] == categoria]
    if em_estoque is not None:
        resultados = [p for p in resultados if p['em_estoque'] == em_estoque]

    resultados.sort(key=lambda x: x.get(ordenar, ''))
    total = len(resultados)
    resultados = resultados[pag['skip']:pag['skip'] + pag['por_pagina']]

    return {
        'total': total,
        'pagina': pag['pagina'],
        'por_pagina': pag['por_pagina'],
        'produtos': resultados
    }

@app.get('/produtos/{produto_id}', response_model=ProdutoResponse, tags=['Produtos'])
def buscar_produto(produto_id: int = Path(ge=1)):
    """Busca produto por ID"""
    if produto_id not in db:
        raise HTTPException(status_code=404, detail=f'Produto {produto_id} nГЈo encontrado')
    return db[produto_id]

@app.patch('/produtos/{produto_id}', response_model=ProdutoResponse, tags=['Produtos'])
def atualizar_produto(produto_id: int, produto: ProdutoUpdate):
    """Atualiza parcialmente um produto"""
    if produto_id not in db:
        raise HTTPException(status_code=404, detail=f'Produto {produto_id} nГЈo encontrado')
    dados = produto.model_dump(exclude_unset=True)
    if not dados:
        raise HTTPException(status_code=400, detail='Nenhum campo para atualizar')
    db[produto_id].update(dados)
    db[produto_id]['atualizado_em'] = datetime.now()
    return db[produto_id]

@app.delete('/produtos/{produto_id}', status_code=204, tags=['Produtos'])
def deletar_produto(produto_id: int):
    """Remove um produto"""
    if produto_id not in db:
        raise HTTPException(status_code=404, detail=f'Produto {produto_id} nГЈo encontrado')
    del db[produto_id]

@app.get('/produtos/stats/resumo', tags=['EstatГӯsticas'])
def estatisticas():
    """EstatГӯsticas dos produtos"""
    if not db:
        return {'total': 0}
    produtos = list(db.values())
    precos = [p['preco'] for p in produtos]
    return {
        'total': len(produtos),
        'preco_medio': sum(precos) / len(precos),
        'preco_min': min(precos),
        'preco_max': max(precos),
        'em_estoque': sum(1 for p in produtos if p['em_estoque']),
        'por_categoria': {cat.value: sum(1 for p in produtos if p['categoria'] == cat) for cat in CategoriaEnum}
    }

