# Usar decorador para verificar mГ©todo
from functools import wraps

def allow_methods(*methods):
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            if request.method not in methods:
                return jsonify({'error': f'MГ©todo {request.method} nГЈo permitido'}), 405
            return f(*args, **kwargs)
        return wrapper
    return decorator

@app.route('/api/resource')
