import tornado.gen
import tornado.ioloop

@tornado.gen.coroutine
def async_task():
    print('Iniciando')
    yield tornado.gen.sleep(2)
    print('Finalizado')

@tornado.gen.coroutine
def main():
    yield async_task()
    print('Main done')

tornado.ioloop.IOLoop.current().run_sync(main)

# Exemplo 2: Coroutine com mГәltiplas operaГ§Гөes
@tornado.gen.coroutine
def fetch_data():
    # Simula chamada assГӯncrona
    result1 = yield async_fetch('url1')
    result2 = yield async_fetch('url2')
    return result1 + result2

# Exemplo 3: Coroutine com paralelismo
@tornado.gen.coroutine
def fetch_parallel():
    result1 = async_fetch('url1')
    result2 = async_fetch('url2')
    results = yield [result1, result2]
    return results

# Exemplo 4: Coroutine com timeout
@tornado.gen.coroutine
def fetch_with_timeout():
    try:
        result = yield tornado.gen.with_timeout(
            tornado.gen.sleep(5),
            async_fetch('url'),
            io_loop=tornado.ioloop.IOLoop.current()
        )
        return result
    except tornado.gen.TimeoutError:
        return 'Timeout'

