@tornado.gen.coroutine
def retry_operation(max_attempts=3):
    for attempt in range(max_attempts):
        try:
            result = yield async_operation()
            return result
        except Exception as e:
            if attempt == max_attempts - 1:
                raise
            yield tornado.gen.sleep(2 ** attempt)

