# Exemplo 2: WebSocket com broadcast
class ChatHandler(tornado.websocket.WebSocketHandler):
    clients = set()

    def open(self):
        self.clients.add(self)
        self.broadcast(f'UsuГЎrio {self.request.remote_ip} entrou')

    def on_message(self, message):
        self.broadcast(f'[{self.request.remote_ip}]: {message}')

    def on_close(self):
        self.clients.remove(self)
        self.broadcast(f'UsuГЎrio {self.request.remote_ip} saiu')

    def broadcast(self, message):
        for client in self.clients:
            client.write_message(message)

