import redis
r = redis.Redis(decode_responses=True)

# Exemplo 1: OperaГ§ГЈo em tipo errado
r.set('string_key', 'valor')
try:
 # Tentar usar operaГ§ГЈo de lista em string
 r.lpush('string_key', 'item')
except redis.ResponseError as e:
 print(f'Erro: {e}')

# Exemplo 2: Comando com sintaxe invГЎlida
try:
 r.execute_command('INVALID_COMMAND')
except redis.ResponseError as e:
 print(f'Erro: {e}')

# Exemplo 3: OperaГ§ГЈo em chave inexistente com tipo especГӯfico
try:
 r.lpop('nao_existe')
except redis.ResponseError:
 print('Chave nГЈo Г© lista')

# Exemplo 4: Tratamento de erro com verificaГ§ГЈo de tipo
key = 'my_key'
key_type = r.type(key)
if key_type == 'string':
 print(r.get(key))
elif key_type == 'list':
 print(r.lrange(key, 0, -1))
else:
 print(f'Tipo nГЈo suportado: {key_type}')

# Exemplo 5: Erro em pipeline com transaГ§ГЈo
r.set('counter', 'not_a_number')
pipe = r.pipeline(transaction=True)
pipe.watch('counter')
try:
 pipe.multi()
 pipe.incr('counter') # Erro: nГЈo Г© inteiro
 pipe.execute()
except redis.ResponseError as e:
 print(f'Erro na transaГ§ГЈo: {e}')
 pipe.reset() # Reseta o pipeline

# Exemplo 6: Erro de limite de memГіria
# Se o Redis estiver com maxmemory configurado
try:
 r.set('large_key', 'x' * (1024 * 1024 * 100)) # 100MB
