import motor.motor_asyncio
import asyncio

async def main():
    client = motor.motor_asyncio.AsyncIOMotorClient('mongodb://localhost:27017')
    db = client['meu_banco']
    collection = db['vendas']

    # Exemplo 1: Agrupamento simples com soma
    pipeline = [
        {'$group': {
            '_id': '$categoria',
            'total': {'$sum': '$valor'},
            'quantidade': {'$sum': 1}
        }}
    ]
    async for doc in collection.aggregate(pipeline):
        print(doc)

    # Exemplo 2: Match + Group + Sort
    pipeline = [
        {'$match': {'status': 'concluido'}},
        {'$group': {
            '_id': '$vendedor',
            'total_vendas': {'$sum': '$valor'},
            'media': {'$avg': '$valor'},
            'max_venda': {'$max': '$valor'}
        }},
        {'$sort': {'total_vendas': -1}},
        {'$limit': 5}
    ]
    print('\nTop 5 vendedores:')
    async for doc in collection.aggregate(pipeline):
        print(f'{doc["_id"]}: R${doc["total_vendas"]:.2f}')

    # Exemplo 3: $project para reformatar
    pipeline = [
        {'$project': {
            'nome_produto': '$produto',
            'preco_final': {
                '$multiply': ['$preco', {'$subtract': [1, '$desconto']}]
            },
            '_id': 0
        }}
    ]
    async for doc in collection.aggregate(pipeline):
        print(doc)

    # Exemplo 4: $lookup (JOIN com outra coleГ§ГЈo)
    pipeline = [
        {'$lookup': {
            'from': 'clientes',
            'localField': 'cliente_id',
            'foreignField': '_id',
            'as': 'cliente_info'
        }},
        {'$unwind': '$cliente_info'},
        {'$project': {
            'produto': 1,
            'valor': 1,
            'cliente_nome': '$cliente_info.nome'
        }}
    ]
    async for doc in collection.aggregate(pipeline):
        print(doc)

    # Exemplo 5: $unwind para desfazer arrays
    pipeline = [
        {'$unwind': '$itens'},
        {'$group': {
            '_id': '$itens.produto',
            'total_vendido': {'$sum': '$itens.quantidade'}
        }},
        {'$sort': {'total_vendido': -1}}
    ]
    async for doc in collection.aggregate(pipeline):
        print(doc)

    # Exemplo 6: $bucket para intervalos
    pipeline = [
        {'$bucket': {
            'groupBy': '$valor',
            'boundaries': [0, 100, 500, 1000, 5000],
            'default': 'Acima de 5000',
            'output': {
                'contagem': {'$sum': 1},
                'media': {'$avg': '$valor'}
            }
        }}
    ]
    async for doc in collection.aggregate(pipeline):
        print(doc)

    # Exemplo 7: Converter resultado para lista
    pipeline = [
        {'$group': {'_id': '$status', 'total': {'$sum': 1}}}
    ]
    resultados = await collection.aggregate(pipeline).to_list(length=None)
    print(f'\nResultados: {resultados}')

asyncio.run(main())

