import motor.motor_asyncio
import asyncio

async def main():
    client = motor.motor_asyncio.AsyncIOMotorClient('mongodb://localhost:27017')
    db = client['meu_banco']

    # Exemplo 1: Criar coleГ§ГЈo simples
    collection = await db.create_collection('nova_colecao')
    print(f'Criada: {collection.name}')

    # Exemplo 2: Capped collection (tamanho fixo)
    collection = await db.create_collection(
        'logs_circular',
        capped=True,
        size=1048576,  # 1MB
        max=1000  # MГЎximo 1000 documentos
    )
    print(f'Capped: {collection.name}')

    # Exemplo 3: Com validaГ§ГЈo de schema
    validator = {
        '$jsonSchema': {
            'bsonType': 'object',
            'required': ['nome', 'email'],
            'properties': {
                'nome': {
                    'bsonType': 'string',
                    'description': 'deve ser string e Г© obrigatГіrio'
                },
                'email': {
                    'bsonType': 'string',
                    'pattern': '^.+@.+\\..+$',
                    'description': 'deve ser email vГЎlido'
                },
                'idade': {
                    'bsonType': 'int',
                    'minimum': 0,
                    'maximum': 150
                }
            }
        }
    }
    collection = await db.create_collection(
        'usuarios_validados',
        validator=validator,
        validationLevel='strict',
        validationAction='error'
    )
    print(f'Com validaГ§ГЈo: {collection.name}')

    # Exemplo 4: Com collation (ordenaГ§ГЈo por idioma)
    collection = await db.create_collection(
        'textos_pt',
        collation={'locale': 'pt', 'strength': 2}
    )
    print(f'Com collation: {collection.name}')

