    # Exemplo 1: $eq - Igual
    docs = await col.find({'preco': {'$eq': 100}}).to_list(None)
    print(f'Igual a 100: {len(docs)}')

    # Exemplo 2: $ne - Diferente
    docs = await col.find({'status': {'$ne': 'inativo'}}).to_list(None)
    print(f'NГЈo inativos: {len(docs)}')

    # Exemplo 3: $gt, $gte, $lt, $lte - ComparaГ§ГЈo
    docs = await col.find({
        'preco': {'$gte': 50, '$lte': 500}
    }).to_list(None)
    print(f'Entre 50 e 500: {len(docs)}')

    # Exemplo 4: $in - Dentro da lista
    docs = await col.find({
        'categoria': {'$in': ['eletronicos', 'informatica']}
    }).to_list(None)
    print(f'Categorias especГӯficas: {len(docs)}')

    # Exemplo 5: $nin - NГЈo estГЎ na lista
    docs = await col.find({
        'status': {'$nin': ['removido', 'expirado']}
    }).to_list(None)
    print(f'NГЈo removidos/expirados: {len(docs)}')

    # Exemplo 6: $and - E lГіgico
    docs = await col.find({
        '$and': [
            {'preco': {'$gt': 100}},
            {'estoque': {'$gt': 0}}
        ]
    }).to_list(None)
    print(f'Caros com estoque: {len(docs)}')

    # Exemplo 7: $or - Ou lГіgico
    docs = await col.find({
        '$or': [
            {'preco': {'$lt': 50}},
            {'promocao': True}
        ]
    }).to_list(None)
    print(f'Baratos ou em promoГ§ГЈo: {len(docs)}')

    # Exemplo 8: $not - NegaГ§ГЈo
    docs = await col.find({
        'preco': {'$not': {'$gt': 1000}}
    }).to_list(None)
    print(f'NГЈo mais que 1000: {len(docs)}')

    # Exemplo 9: $exists - Campo existe
    docs = await col.find({'desconto': {'$exists': True}}).to_list(None)
    print(f'Com desconto: {len(docs)}')

    # Exemplo 10: $type - Tipo do campo
    docs = await col.find({'preco': {'$type': 'double'}}).to_list(None)
    print(f'PreГ§o Г© double: {len(docs)}')

    # Exemplo 11: $regex - ExpressГЈo regular
    docs = await col.find({
        'nome': {'$regex': '^Note', '$options': 'i'}
    }).to_list(None)
    print(f'ComeГ§a com Note: {len(docs)}')

    # Exemplo 12: $size - Tamanho de array
    docs = await col.find({'tags': {'$size': 3}}).to_list(None)
    print(f'Exatamente 3 tags: {len(docs)}')

    # Exemplo 13: $all - Array contГ©m todos
    docs = await col.find({
        'tags': {'$all': ['novo', 'destaque']}
    }).to_list(None)
