import motor.motor_asyncio
import asyncio
from datetime import datetime

async def main():
    client = motor.motor_asyncio.AsyncIOMotorClient('mongodb://localhost:27017')
    db = client['meu_banco']
    col = db['usuarios']

    # Exemplo 1: $set - Definir valor
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$set': {'email': 'joao@novo.com', 'ativo': True}}
    )
    print('$set aplicado')

    # Exemplo 2: $unset - Remover campo
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$unset': {'campo_antigo': '', 'temp': ''}}
    )
    print('$unset aplicado')

    # Exemplo 3: $inc - Incrementar
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$inc': {'pontos': 10, 'nivel': 1}}
    )
    print('$inc aplicado')

    # Exemplo 4: $mul - Multiplicar
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$mul': {'salario': 1.10}}  # Aumento de 10%
    )
    print('$mul aplicado')

    # Exemplo 5: $min / $max - Definir mГӯnimo/mГЎximo
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$min': {'menor_nota': 7}, '$max': {'maior_nota': 10}}
    )
    print('$min/$max aplicado')

    # Exemplo 6: $rename - Renomear campo
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$rename': {'nome_antigo': 'nome_novo'}}
    )
    print('$rename aplicado')

    # Exemplo 7: $currentDate - Data atual
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$currentDate': {'ultimo_acesso': True, 'log.data': {'$type': 'timestamp'}}}
    )
    print('$currentDate aplicado')

    # Exemplo 8: $push - Adicionar ao array
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$push': {'hobbies': 'nataГ§ГЈo'}}
    )
    print('$push aplicado')

    # Exemplo 9: $push com $each, $sort, $slice
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$push': {
            'notas': {
                '$each': [8, 9, 7],
                '$sort': -1,
                '$slice': 5  # Manter apenas 5 melhores
            }
        }}
    )
    print('$push com modificadores aplicado')

    # Exemplo 10: $addToSet - Adicionar sem duplicar
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$addToSet': {'tags': 'vip'}}
    )
    print('$addToSet aplicado')

    # Exemplo 11: $pull - Remover do array
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$pull': {'hobbies': 'nataГ§ГЈo'}}
    )
    print('$pull aplicado')

    # Exemplo 12: $pop - Remover primeiro/Гәltimo do array
    await col.update_one(
        {'nome': 'JoГЈo'},
        {'$pop': {'notas': 1}}  # 1 = Гәltimo, -1 = primeiro
    )
    print('$pop aplicado')

asyncio.run(main())

import motor.motor_asyncio
import asyncio
from pymongo import GEO2DSPHERE

async def main():
    client = motor.motor_asyncio.AsyncIOMotorClient('mongodb://localhost:27017')
    db = client['meu_banco']
    col = db['lugares']

    # Criar Гӯndice geoespacial
    await col.create_index([('localizacao', GEO2DSPHERE)])

    # Inserir dados
    await col.insert_many([
        {
            'nome': 'Restaurante A',
            'localizacao': {'type': 'Point', 'coordinates': [-46.6334, -23.5505]}
        },
        {
            'nome': 'Restaurante B',
            'localizacao': {'type': 'Point', 'coordinates': [-46.6544, -23.5635]}
        },
        {
            'nome': 'Restaurante C',
            'localizacao': {'type': 'Point', 'coordinates': [-46.6258, -23.5338]}
        }
    ])

    # Exemplo 1: Buscar prГіximos a um ponto
    cursor = col.find({
        'localizacao': {
            '$near': {
                '$geometry': {
                    'type': 'Point',
                    'coordinates': [-46.6340, -23.5489]
                },
                '$maxDistance': 5000  # 5km em metros
            }
        }
    })
    print('PrГіximos (atГ© 5km):')
    async for doc in cursor:
        print(f'  {doc["nome"]}')

    # Exemplo 2: Buscar dentro de um polГӯgono
    cursor = col.find({
        'localizacao': {
            '$geoWithin': {
                '$geometry': {
                    'type': 'Polygon',
                    'coordinates': [[
                        [-46.66, -23.56],
                        [-46.62, -23.56],
                        [-46.62, -23.53],
                        [-46.66, -23.53],
                        [-46.66, -23.56]
                    ]]
                }
            }
        }
    })
    print('\nDentro da ГЎrea:')
    async for doc in cursor:
        print(f'  {doc["nome"]}')

    # Exemplo 3: AgregaГ§ГЈo com $geoNear
    pipeline = [
        {
            '$geoNear': {
                'near': {'type': 'Point', 'coordinates': [-46.6340, -23.5489]},
                'distanceField': 'distancia',
                'maxDistance': 10000,
                'spherical': True
            }
        }
    ]
    print('\nCom distГўncia:')
    async for doc in col.aggregate(pipeline):
        print(f'  {doc["nome"]}: {doc["distancia"]:.0f} metros')

asyncio.run(main())

