from graphql import build_schema, parse, subscribe
import asyncio

# Exemplo 1: Subscription bГЎsica
schema = build_schema('''
type Subscription {
    counter: Int
}
type Query {
    dummy: String
}
''')

async def counter_generator(obj, info):
    for i in range(5):
        await asyncio.sleep(0.1)
        yield {'counter': i}

root = {'counter': counter_generator}

async def run_subscription():
    query = parse('subscription { counter }')
    result = await subscribe(schema, query, root)

    print('Eventos:')
    async for event in result:
        print(f'  - {event.data}')

asyncio.run(run_subscription())

# Exemplo 2: Com filtro
async def filtered_events(obj, info, min_value=0):
    for i in range(10):
        if i >= min_value:
            yield {'value': i}
            await asyncio.sleep(0.05)

