from graphql import GraphQLObjectType, GraphQLField, GraphQLString, GraphQLSchema, graphql_sync

# Exemplo 1: Acessando propriedades de info
def detailed_resolver(obj, info):
    details = [
        f'field_name: {info.field_name}',
        f'parent_type: {info.parent_type.name}',
        f'return_type: {info.return_type}',
        f'path: {info.path.key}'
    ]
    return ' | '.join(details)

schema = GraphQLSchema(
    query=GraphQLObjectType(
        'Query',
        lambda: {
            'details': GraphQLField(
                GraphQLString,
                resolve=detailed_resolver
            )
        }
    )
)

result = graphql_sync(schema, '{ details }')
print(f'Info: {result.data["details"]}')

# Exemplo 2: Acessando schema e operaГ§ГЈo
def schema_info_resolver(obj, info):
    return f'Schema: {info.schema.query_type.name}, Op: {info.operation.operation.value}'

schema2 = GraphQLSchema(
    query=GraphQLObjectType(
        'Query',
        lambda: {
            'schemaInfo': GraphQLField(
                GraphQLString,
                resolve=schema_info_resolver
            )
        }
    )
)

