from graphql import GraphQLObjectType, GraphQLField, GraphQLString, GraphQLSchema, graphql_sync
from graphql.error import located_error, GraphQLError

# Exemplo 1: Erro com localizaГ§ГЈo
def error_resolver(obj, info):
    original = ValueError('Valor invГЎlido')
    raise located_error(original, info.field_nodes, info.path.as_list())

schema = GraphQLSchema(
    query=GraphQLObjectType(
        'Query',
        lambda: {
            'failing': GraphQLField(
                GraphQLString,
                resolve=error_resolver
            )
        }
    )
)

result = graphql_sync(schema, '{ failing }')
if result.errors:
    error = result.errors[0]
    print(f'Erro: {error.message}')
    print(f'LocalizaГ§ГЈo: {error.locations}')
    print(f'Path: {error.path}')

# Exemplo 2: Erro original preservado
if result.errors:
    original = result.errors[0].original_error
    if original:
        print(f'\nErro original: {type(original).__name__}')

