# Exemplo 3: Adicionando token automaticamente
class AuthInterceptor:
    def __init__(self, get_token_func):
        self.get_token = get_token_func

    def intercept(self, continuation, call_details, request):
        token = self.get_token()
        metadata = [('authorization', f'Bearer {token}')]

        new_details = call_details._replace(metadata=metadata)
        return continuation(new_details, request)

