# Exemplo 1: Tratando rate limit
from censys.search import CensysHosts
from censys.common.exceptions import CensysRateLimitException
import time

h = CensysHosts()

def safe_search(query, max_retries=3):
    for attempt in range(max_retries):
        try:
            return h.search(query, per_page=10)
        except CensysRateLimitException as e:
            wait_time = 2 ** attempt  # Exponential backoff
            print(f'Rate limit atingido. Aguardando {wait_time}s...')
            time.sleep(wait_time)
    raise Exception('Max retries exceeded')

results = safe_search('service.service_name: HTTP')

# Exemplo 2: Verificar cota antes de buscar
quota = h.quota()
if quota['remaining'] > 0:
    results = h.search('query', per_page=quota['remaining'])
else:
    print('Cota esgotada. Aguarde o prГіximo mГӘs.')

