import httpx

# String com caminho do certificado (cert+key combinado)
try:
    r = httpx.get('https://httpbin.org/get', cert='/path/to/client.pem')
except Exception as e:
    print(f'Cert file: {type(e).__name__}')

# Tupla (cert, key separados)
try:
    r = httpx.get(
        'https://httpbin.org/get',
        cert=('/path/to/client.cert', '/path/to/client.key')
    )
except Exception as e:
    print(f'Cert tuple: {type(e).__name__}')

# No Client
try:
    with httpx.Client(cert='/path/to/client.pem') as client:
        r = client.get('https://httpbin.org/get')
except Exception as e:
    print(f'Client cert: {type(e).__name__}')

