import httpx

# Exemplo 1: Timeout via extensions
r = httpx.get(
    'https://httpbin.org/get',
    extensions={'timeout': {'connect': 5.0, 'read': 10.0, 'write': 5.0, 'pool': 5.0}}
)
print('Extensions timeout:', r.status_code)

# Exemplo 2: Desabilitar compressГЈo
r = httpx.get(
    'https://httpbin.org/get',
    extensions={'force': {'disable_compression': True}}
)
print('No compress:', r.status_code)

# Exemplo 3: Com Client
with httpx.Client() as client:
    r = client.get(
        'https://httpbin.org/get',
        extensions={'timeout': {'read': 5.0}}
    )
    print('Client ext:', r.status_code)

