import mechanize, re
br = mechanize.Browser()
br.set_handle_robots(False)
br.open('http://www.example.com/')

# Exemplo 1: Link inexistente por texto
try:
    link = br.find_link(text='link-que-nao-existe')
except mechanize.LinkNotFoundError as e:
    print('LinkNotFoundError:', e)

# Exemplo 2: follow_link com texto inexistente
try:
    br.follow_link(text='Nao Existe')
except mechanize.LinkNotFoundError as e:
    print('Nao encontrado:', e)

# Exemplo 3: Prevenir com verificacao previa
links = list(br.links(text='texto-buscado'))
if links:
    br.follow_link(links[0])
else:
    print('Link nao encontrado, pulando')

import mechanize
br = mechanize.Browser()
br.set_handle_robots(False)

# Exemplo 1: Host inexistente
try:
    br.open('http://host-que-nao-existe-xyz.com/')
except mechanize.URLError as e:
    print('URLError:', e.reason)

# Exemplo 2: Conexao recusada
try:
    br.open('http://localhost:19999/')  # porta fechada
except mechanize.URLError as e:
    print('Conexao recusada:', e.reason)

# Exemplo 3: Capturar hierarquia completa de excecoes
try:
    br.open('http://host-invalido.xyz/')
except mechanize.HTTPError as e:
    print('HTTP Error:', e.code)
except mechanize.URLError as e:
    print('URL Error (sem conexao):', e.reason)
except Exception as e:
    print('Outro erro:', e)

import mechanize
br = mechanize.Browser()

# Exemplo 1: Acessar forms sem ter aberto pagina
try:
    forms = list(br.forms())
except mechanize.BrowserStateError as e:
    print('BrowserStateError:', e)

# Exemplo 2: select_form sem pagina carregada
try:
    br.select_form(nr=0)
except mechanize.BrowserStateError as e:
    print('Sem pagina HTML:', e)

# Exemplo 3: back() sem historico
try:
    br.open('http://www.example.com/')
    br.back()
    br.back()  # nao ha historico suficiente
except mechanize.BrowserStateError as e:
    print('Sem historico:', e)

import mechanize
br = mechanize.Browser()
br.set_handle_robots(False)
br.open('http://www.example.com/login')
br.select_form(nr=0)
form = br.form

# Exemplo 1: Controle por nome inexistente
try:
    ctrl = form.find_control('campo-que-nao-existe')
except mechanize.ControlNotFoundError as e:
    print('ControlNotFoundError:', e)

# Exemplo 2: Controle pelo tipo errado
try:
    ctrl = form.find_control(type='file')  # se nao existir input type=file
except mechanize.ControlNotFoundError as e:
    print('Sem campo file:', e)

# Exemplo 3: Verificar existencia antes de acessar
def campo_existe(form, nome):
    try:
        form.find_control(nome)
        return True
    except mechanize.ControlNotFoundError:
        return False

if campo_existe(form, 'email'):
    form['email'] = 'usuario@exemplo.com'
    print('Email preenchido')
else:
    print('Campo email nao encontrado')
